#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

__kernel void benchmark_func(const class_T seed, __global class_T* c) {
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);

  const size_t lid = get_local_id(0);
  const size_t lsize = get_local_size(0);
  const size_t group = get_group_id(0);

  size_t base;
  size_t stride;

#ifdef BLOCK_STRIDED
  base = group * lsize * (size_t)ELEMENTS_PER_THREAD * (size_t)FUSION_DEGREE + lid;
  stride = lsize;
#else
  base = gid;
  stride = gsize;
#endif

  class_T sum = (class_T)(0);

  for (size_t f = 0; f < (size_t)FUSION_DEGREE; ++f) {
    const size_t fusion_base = base + f * (size_t)ELEMENTS_PER_THREAD * stride;

    for (size_t e = 0; e < (size_t)ELEMENTS_PER_THREAD; ++e) {
      const size_t idx = fusion_base + e * stride;
      class_T t = c[idx];

      for (int it = 0; it < COMPUTE_ITERATIONS; ++it) {
        t = t * t + seed;
      }

      sum += t;
    }
  }

  c[base] = sum;
}
